ALTO_VALOR_LOGO = "data:image/png;base64,"
def _inject_brand_logo(html: str) -> str:
    """Swap the design's text brand-mark for the real Alto Valor logo image
    in the redesigned pages (Avaliação de Agentes, Sem Resposta) so they match
    the other tabs. Matches the whole `<div class="brand">…</div>` block up to
    the following `<nav` and replaces it with the logo lockup."""
    import re as _re_b
    brand = (
        '<div class="brand" style="justify-content:center;padding:20px 18px 16px">'
        f'<img src="{ALTO_VALOR_LOGO}" alt="Alto Valor Investimentos" '
        'style="width:100%;max-width:172px;height:auto;object-fit:contain;display:block" />'
        '</div>'
    )
    return _re_b.sub(
        r'<div class="brand">[\s\S]*?</div>\s*(?=<nav)',
        brand + "\n  ",
        html,
        count=1,
    )


