COMPANY_CHANNELS = set(COMPANY_CHANNELS_MAP.keys())


def _req_canal(request, default: str = "5519997733651") -> str:
    """Read & validate the 'canal' query param against the known company channels.
    The value flows into many hrefs, so an unknown/forged value (XSS payloads,
    etc.) must never survive — it falls back to ``default``."""
    raw = (request.query_params.get("canal", default) or "").strip()
    return raw if raw in COMPANY_CHANNELS else default


def _formula_safe(v):
    """Neutralize spreadsheet formula/DDE injection in exported cells: prefix a
    leading =, +, -, @, tab, CR or LF with a quote so Excel/Sheets treat the cell
    as text. Non-strings (numbers) pass through unchanged."""
    if isinstance(v, str) and v[:1] in ("=", "+", "-", "@", "\t", "\r", "\n"):
        return "'" + v
    return v


HOUR_START, HOUR_END = 6, 19

# Zenvia conversation deep-link template. "{id}" is replaced with the
# conversation.id from the webhook payload (it matches the id Zenvia uses in
# its own URL path — verified against a real conversation). The "?g=" group
# param is REQUIRED — without it Zenvia opens the inbox with no group selected
# ("Selecione um grupo") and shows nothing.
#
# IMPORTANT — Zenvia has NO real URL deep-link to a conversation. The
# conversation.id in the path is only STATE-REFLECTION: it appears in the
# address bar while you're already inside the conversation, but loading the URL
# cold does NOT open it (the SPA lands on the inbox / search list). Confirmed in
# prod against two real conversations. The best achievable via URL is to append
# "&search=<client name>": Zenvia runs the inbox search and lands on the list
# already FILTERED to the exact client — one click on the result opens the
# conversation. So _zenvia_url() always appends the search term; that mirrors
# the URL Zenvia produces when you search the inbox by hand. There is no URL
# that opens the conversation pane directly on a cold load.
# Leave the template empty to omit the Zenvia link entirely.
ZENVIA_CONV_URL_TEMPLATE = "https://app.zenvia.com/sales-chat/inbox/all/{id}?g=69a88feecfe7701db3cb102f"


def _zenvia_url(conv_id: str, search: str = "") -> str:
    """Build the best-effort Zenvia link for a conversation.

    Zenvia has no true URL deep-link to a conversation (the path id is just
    state-reflection — see the note on ZENVIA_CONV_URL_TEMPLATE). Appending
    "&search=<client name>" is the best achievable: it lands on the inbox
    already filtered to the exact client, one click away from the conversation.
    """
    if not (ZENVIA_CONV_URL_TEMPLATE and conv_id):
        return ""
    url = ZENVIA_CONV_URL_TEMPLATE.replace("{id}", conv_id)
    s = (search or "").strip()
    if s:
        from urllib.parse import quote_plus
        url += "&search=" + quote_plus(s)
    return url

# ── Business-hours helpers (Sem Resposta detection) ──────────────────────────
# Working window used to decide whether a client was really "left waiting":
# nights and weekends don't count, so a Friday-evening message isn't flagged
# as "60h sem resposta" on Monday — it's ~1 business hour.
BIZ_DAY_START, BIZ_DAY_END = 9, 18   # Mon–Fri, Brasília


def _biz_hours_between(start, end) -> float:
    """Number of business hours (Mon–Fri, BIZ_DAY_START–BIZ_DAY_END, Brasília)
    elapsed between two tz-aware datetimes. 0 if end<=start or invalid."""
    if not start or not end:
        return 0.0
    s = start.astimezone(BRASILIA)
    e = end.astimezone(BRASILIA)
    if e <= s:
        return 0.0
    total = 0.0
    day = s.date()
    last = e.date()
    while day <= last:
        if day.weekday() < 5:  # Mon–Fri
            ws = datetime(day.year, day.month, day.day, BIZ_DAY_START, 0, 0, tzinfo=BRASILIA)
            we = datetime(day.year, day.month, day.day, BIZ_DAY_END, 0, 0, tzinfo=BRASILIA)
            lo = s if s > ws else ws
            hi = e if e < we else we
            if hi > lo:
                total += (hi - lo).total_seconds() / 3600.0
        day += timedelta(days=1)
    return round(total, 1)

