            f'color:{"#ef4444" if not _suc else "#0fa968"};font-weight:700;flex-shrink:0">{"!" if not _suc else "&#10003;"}</div>'
            f'<span style="font-size:12.5px;color:{_who_col};font-weight:600">'
            f'{html_mod.escape(str(_le.get("who","?")))}</span></div>'
