@router.post("/dashboard/ack-alert", include_in_schema=False)
async def ack_alert_endpoint(request: Request, db: Session = Depends(get_db)):
    if not _check_auth(request):
        return JSONResponse({"error": "unauth"}, status_code=401)
    try:
        body = await request.json()
    except Exception:
        return JSONResponse({"error": "bad json"}, status_code=400)
    phone_key = (body.get("phone_key") or "").strip()
    if not phone_key:
        return JSONResponse({"error": "missing phone_key"}, status_code=400)
    # `status` is "ok" (false positive / no real issue) or "problema"
    # (confirmed compliance issue). Default to "ok" for backward compatibility
    # with old payloads that didn't send the field.
    status = (body.get("status") or "ok").strip().lower()
    if status not in ("ok", "problema"):
        status = "ok"
    acked = _get_acked_alerts(db)
    acked[phone_key] = {
        "agent": body.get("agent", ""),
        "snippet": body.get("snippet", ""),
        "display_name": body.get("display_name", phone_key),
        "acked_at": datetime.now(BRASILIA).isoformat(),
        "status": status,
    }
    _save_acked_alerts(db, acked)
    return JSONResponse({"ok": True, "status": status})


@router.post("/dashboard/unack-alert", include_in_schema=False)
async def unack_alert_endpoint(request: Request, db: Session = Depends(get_db)):
    if not _check_auth(request):
        return JSONResponse({"error": "unauth"}, status_code=401)
    try:
        body = await request.json()
    except Exception:
        return JSONResponse({"error": "bad json"}, status_code=400)
    phone_key = (body.get("phone_key") or "").strip()
    acked = _get_acked_alerts(db)
    acked.pop(phone_key, None)
    _save_acked_alerts(db, acked)
    return JSONResponse({"ok": True})


@router.post("/dashboard/dismiss-sr", include_in_schema=False)
async def dismiss_sr_endpoint(request: Request, db: Session = Depends(get_db)):
    """Mark a Sem Resposta candidate as dismissed (green ✓).
    Stores {phone: last_event_id}. The dismissal only holds while the
    conversation is unchanged — if the client sends a NEW message
    (different last_event_id), it re-enters the queue automatically.
    """
    if not _check_auth(request):
        return JSONResponse({"error": "unauth"}, status_code=401)
    try:
        body = await request.json()
    except Exception:
        return JSONResponse({"error": "bad json"}, status_code=400)
    phone = (body.get("phone") or "").strip()
    if not phone:
        return JSONResponse({"error": "missing phone"}, status_code=400)
    last_event_id = (body.get("last_event_id") or "").strip()
    dismissed = _get_dismissed_sr(db)
    dismissed[phone] = last_event_id
    _save_dismissed_sr(db, dismissed)
    # Marking resolved clears any 'em tratativa' flag (it's now done).
    trat = _get_tratativa_sr(db)
    if trat.pop(phone, None) is not None:
        _save_tratativa_sr(db, trat)
    return JSONResponse({"ok": True})


@router.post("/dashboard/tratativa-sr", include_in_schema=False)
async def tratativa_sr_endpoint(request: Request, db: Session = Depends(get_db)):
    """Toggle the 'Em tratativa' flag on a Sem Resposta conversation.

    Body: {phone, last_event_id, on}. Stores {phone: last_event_id} so a new
    client message (different id) clears the flag automatically. The
    conversation is NOT removed from the queue — only marked/de-prioritized.
    """
    if not _check_auth(request):
        return JSONResponse({"error": "unauth"}, status_code=401)
    try:
        body = await request.json()
    except Exception:
        return JSONResponse({"error": "bad json"}, status_code=400)
    phone = (body.get("phone") or "").strip()
    if not phone:
        return JSONResponse({"error": "missing phone"}, status_code=400)
    on = bool(body.get("on", True))
    last_event_id = (body.get("last_event_id") or "").strip()
    trat = _get_tratativa_sr(db)
    if on:
        trat[phone] = last_event_id
    else:
        trat.pop(phone, None)
    _save_tratativa_sr(db, trat)
    return JSONResponse({"ok": True})


_SCORE_VERSION = "v3"
# Cobertura: a IA também diz QUAIS produtos o assessor ofereceu (mesma chamada).
_COV_VERSION = "v1"
_COV_CATALOG = "; ".join(f"{tid} — {label}" for tid, label, *_ in TOPIC_RULES)
_COV_PRODUCT_IDS = {tid for tid, *_ in TOPIC_RULES}
_SCORE_SYSTEM = """Você é avaliador sênior de qualidade de atendimento de uma assessoria de \
investimentos (Alto Valor / XP). Avalie o desempenho do ASSESSOR numa conversa de WhatsApp \
com um CLIENTE.

═══════ PASSO 1 — CLASSIFIQUE O TIPO DA CONVERSA ═══════
- "duas_vias": houve troca real — cliente perguntou/respondeu e assessor interagiu. AVALIÁVEL.
- "cliente_sumiu": assessor respondeu adequadamente mas o CLIENTE parou de responder. \
AVALIÁVEL, porém NUNCA penalize o assessor pelo silêncio do cliente — avalie só o que o assessor fez.
- "so_saida": apenas mensagens do assessor (template, disparo, follow-up) sem o cliente \
ter interagido de verdade. NÃO AVALIÁVEL (avaliavel=false, nota=null).
- "social": apenas saudações/agradecimentos sem demanda real. NÃO AVALIÁVEL (avaliavel=false, nota=null).

═══════ PASSO 2 — SE AVALIÁVEL, DÊ UMA NOTA 0-10 ═══════
Rubrica ancorada:
- 9-10: Excelente. Respondeu rápido, com clareza e profundidade, proativo, cliente plenamente atendido.
- 7-8: Bom. Atendeu a necessidade com qualidade, pequenas oportunidades de melhoria.
- 5-6: Regular. Resolveu o essencial mas com lacunas (demora, resposta incompleta, pouca proatividade).
- 3-4: Ruim. Falhas claras: deixou dúvida sem resposta, foi vago, demorou muito por culpa própria.
- 0-2: Crítico. Ignorou o cliente, deu informação errada, foi rude, ou cometeu erro grave de conduta.

Critérios (avalie só o que está sob controle do ASSESSOR):
- Tempo de resposta do assessor (não conte silêncio causado pelo cliente)
- Clareza, completude e correção técnica das respostas
- Cordialidade e tom profissional
- Se a necessidade do cliente foi efetivamente atendida
- Proatividade (antecipar, sugerir próximos passos)

═══════ PASSO 3 — ESTRUTURE OS APRENDIZADOS ═══════
- pontos_positivos: o que o assessor fez BEM (frases curtas, objetivas, reaproveitáveis)
- erros: falhas concretas COMETIDAS nesta conversa (vazio se não houver). Ex: "Não respondeu a \
pergunta sobre taxa do CDB", "Demorou 2 dias para retornar"
- pontos_melhoria: sugestões acionáveis para o assessor melhorar (mesmo em notas boas)

Use frases curtas e PADRONIZADAS (reaproveitáveis entre conversas), não descrições longas.

O campo "motivo" deve ser o MOTIVO DO CONTATO em 2-5 palavras (o que o cliente queria). \
Ex: "Cotação de CDB", "Pedido de resgate", "Dúvida sobre rendimento", "Abertura de conta", \
"Reclamação de taxa". Se for disparo/social, use "Disparo" ou "Social".

Responda SOMENTE em JSON, sem texto adicional, sem markdown:
{"tipo":"duas_vias","avaliavel":true,"nota":8,"motivo":"Cotação de CDB","resumo":"frase de 1-2 linhas","pontos_positivos":["..."],"erros":["..."],"pontos_melhoria":["..."]}

Se não avaliável: {"tipo":"so_saida","avaliavel":false,"nota":null,"motivo":"Disparo","resumo":"motivo","pontos_positivos":[],"erros":[],"pontos_melhoria":[]}""" + f"""

═══════ PASSO 4 — PRODUTOS QUE O ASSESSOR OFERECEU ═══════
Acrescente ao JSON o campo "produtos_oferecidos": lista de IDs dos produtos que o ASSESSOR (não o cliente) trouxe, sugeriu ou ofereceu DE VERDADE nesta conversa. NÃO inclua produto que apareceu só porque o CLIENTE perguntou, nem menção de passagem. Lista vazia [] se o assessor não ofereceu nenhum.
Produtos disponíveis (id — nome): {_COV_CATALOG}
Exemplo de JSON COMPLETO com o campo: {{"tipo":"duas_vias","avaliavel":true,"nota":8,"motivo":"Cotação de CDB","resumo":"...","pontos_positivos":["..."],"erros":[],"pontos_melhoria":["..."],"produtos_oferecidos":["renda_fixa"]}}"""


def _build_transcript(msg_tuples: list) -> str:
    lines = []
    for d, txt, ts in msg_tuples[-40:]:
        who = "CLIENTE" if (d or "").upper() == "IN" else "ASSESSOR"
        ts_str = ts.strftime("%d/%m %H:%M") if ts else "?"
        body_txt = (txt or "").strip().replace("\n", " ")
        if len(body_txt) > 500:
            body_txt = body_txt[:500] + "…"
        lines.append(f"[{ts_str}] {who}: {body_txt}")
    return "\n".join(lines)


def _call_score_llm(transcript: str) -> dict:
    """Call Claude and return parsed score dict. Raises on failure."""
    import anthropic as _anthropic, re as _re
    client = _anthropic.Anthropic(api_key=settings.ANTHROPIC_API_KEY)
    resp = client.messages.create(
        model=settings.ANTHROPIC_MODEL_BULK,
        max_tokens=750,
        system=_SCORE_SYSTEM,
        messages=[{"role": "user", "content": f"Avalie a conversa abaixo:\n\n{transcript}"}],
    )
    raw = "".join(b.text for b in resp.content if getattr(b, "type", "") == "text").strip()
    m = _re.search(r"\{[\s\S]*\}", raw)
    data = json.loads(m.group(0)) if m else {}

    tipo = (data.get("tipo") or "duas_vias").strip().lower()
    if tipo not in ("duas_vias", "cliente_sumiu", "so_saida", "social"):
        tipo = "duas_vias"
    avaliavel = bool(data.get("avaliavel", tipo in ("duas_vias", "cliente_sumiu")))

    raw_nota = data.get("nota")
    if avaliavel and raw_nota is not None:
        try:
            nota = max(0, min(10, int(raw_nota)))
        except (TypeError, ValueError):
            nota = None
    else:
        nota = None

    return {
        "tipo":             tipo,
        "avaliavel":        avaliavel,
        "nota":             nota,
        "motivo":           str(data.get("motivo", ""))[:80],
        "resumo":           str(data.get("resumo", ""))[:300],
        "pontos_positivos": [str(x)[:200] for x in (data.get("pontos_positivos") or [])[:5]],
        "erros":            [str(x)[:200] for x in (data.get("erros")            or [])[:5]],
        "pontos_melhoria":  [str(x)[:200] for x in (data.get("pontos_melhoria")  or [])[:5]],
        "produtos":         [p for p in (data.get("produtos_oferecidos") or [])
                             if isinstance(p, str) and p in _COV_PRODUCT_IDS][:14],
    }


def _upsert_coverage(db: Session, phone: str, last_event_id: str, canal: str,
                     agent: str, produtos) -> None:
    """Persist which shelf products the advisor offered (Cobertura). Rides the
    weekly score call — see ConversationCoverage."""
    from app.models import ConversationCoverage as _CC
    prods = [p for p in (produtos or []) if p in _COV_PRODUCT_IDS]
    row = db.get(_CC, (phone, last_event_id))
    now_utc = datetime.now(timezone.utc)
    if row:
        row.canal = canal; row.agent = agent; row.produtos = prods
        row.cov_version = _COV_VERSION; row.scored_at = now_utc
    else:
        db.add(_CC(phone=phone, last_event_id=last_event_id, canal=canal,
                   agent=agent, produtos=prods, cov_version=_COV_VERSION, scored_at=now_utc))
    db.commit()


def _upsert_score(db: Session, phone: str, last_event_id: str, canal: str, scored: dict) -> None:
    from app.models import ConversationScore as _CS
    row = db.get(_CS, (phone, last_event_id))
    now_utc = datetime.now(timezone.utc)
    # nota is non-nullable in DB; store -1 sentinel for non-evaluable convs
    nota_db = scored["nota"] if scored.get("nota") is not None else -1
    if row:
        row.nota             = nota_db
        row.tipo             = scored.get("tipo")
        row.avaliavel        = 1 if scored.get("avaliavel") else 0
        row.motivo           = scored.get("motivo") or ""
        row.resumo           = scored["resumo"]
        row.pontos_positivos = scored["pontos_positivos"]
        row.erros            = scored.get("erros") or []
        row.pontos_melhoria  = scored["pontos_melhoria"]
        row.score_version    = _SCORE_VERSION
        row.scored_at        = now_utc
    else:
        row = _CS(
            phone=phone, last_event_id=last_event_id, canal=canal,
            nota=nota_db, tipo=scored.get("tipo"),
            avaliavel=1 if scored.get("avaliavel") else 0,
            motivo=scored.get("motivo") or "",
            resumo=scored["resumo"],
            pontos_positivos=scored["pontos_positivos"],
            erros=scored.get("erros") or [],
            pontos_melhoria=scored["pontos_melhoria"],
            score_version=_SCORE_VERSION, scored_at=now_utc,
        )
        db.add(row)
    db.commit()


@router.post("/dashboard/score-conv", include_in_schema=False)
def score_conv_endpoint(request: Request, body: dict = Body(default={}), db: Session = Depends(get_db)):
    """Score a single conversation 0-10.  Uses cache: if already scored with
    the current last_event_id, returns the cached result immediately.
    Sync def → runs in threadpool so the blocking LLM/DB work never freezes
    the event loop (which would stall /health and webhooks)."""
    if not _check_auth(request):
        return JSONResponse({"error": "unauth"}, status_code=401)
    if not isinstance(body, dict):
        return JSONResponse({"error": "bad json"}, status_code=400)

    phone = (body.get("phone") or "").strip()
    canal = (body.get("canal") or "5519997733651").strip()
    if not phone:
        return JSONResponse({"error": "missing phone"}, status_code=400)

    if not settings.ANTHROPIC_API_KEY:
        return JSONResponse({"error": "ANTHROPIC_API_KEY não configurada"}, status_code=503)

    from app.crud import get_events_since, get_agent_mappings
    from app.models import ConversationScore as _CS

    cutoff_utc = (datetime.now(BRASILIA) - timedelta(days=30)).replace(
        hour=0, minute=0, second=0, microsecond=0
    ).astimezone(timezone.utc)

    raw_evs = get_events_since(db, since=cutoff_utc, limit=30000)
    raw_evs = _filter_events_by_channel(raw_evs, canal)
    cam = get_agent_mappings(db)

    groups_orm, _ = _group_events(raw_evs, cam)
    cp = _real_phone(canal)

    msg_tuples = []
    last_event_id = ""
    _epoch = datetime.min.replace(tzinfo=timezone.utc)
    for key, evs in groups_orm.items():
        if _real_phone(key) != phone or _real_phone(key) == cp:
            continue
        sorted_evs = sorted(
            [e for e in evs if (e.raw_payload or {}).get("type", "").upper()
             not in ("MESSAGE_STATUS", "CONVERSATION_STATUS")],
            key=lambda e: e.received_at or _epoch
        )
        for ev in sorted_evs:
            _p   = ev.raw_payload or {}
            _txt = _extract_content_preview(_p, max_len=1000) or ""
            _ts  = ev.received_at.astimezone(BRASILIA) if ev.received_at else None
            if _txt:
                msg_tuples.append((_extract_direction(_p), _txt, _ts))
        if sorted_evs:
            last_event_id = str(sorted_evs[-1].id)

    if not msg_tuples:
        db.close()
        return JSONResponse({"error": "Sem mensagens para avaliar"}, status_code=404)

    # Cache hit?
    if last_event_id:
        cached = db.get(_CS, (phone, last_event_id))
        if cached and cached.score_version == _SCORE_VERSION:
            db.close()
            return JSONResponse({
                "nota": cached.nota, "resumo": cached.resumo or "",
                "pontos_positivos": cached.pontos_positivos or [],
                "pontos_melhoria":  cached.pontos_melhoria  or [],
                "from_cache": True,
            })

    from app.services import llm_budget as _llm
    if not _llm.try_consume(db, feature="avaliacao"):
        db.close()
        return JSONResponse({"error": "Limite diário de avaliações por IA atingido. Tente amanhã."}, status_code=429)

    try:
        scored = _call_score_llm(_build_transcript(msg_tuples))
        if last_event_id:
            _upsert_score(db, phone, last_event_id, canal, scored)
            _upsert_coverage(db, phone, last_event_id, canal,
                             cam.get(phone) or "Sem atendente", scored.get("produtos"))
        db.close()
        return JSONResponse(scored)
    except Exception as exc:
        db.close()
        import logging as _log
        _log.getLogger(__name__).error("score-conv error: %s", exc)
        return JSONResponse({"error": "Erro ao avaliar a conversa"}, status_code=500)


