def run_score_scan(db, canal: str = "5519997733651", days: int = 30) -> dict:
    """Score every conversation in the window, server-side (no browser).

    Skips conversations already scored for their current state (cache by
    phone+last_event_id+version), so re-runs only pay for what changed.
    Used by the cron endpoint and by the weekly auto-score scheduler.
    """
    from app.crud import get_events_since, get_agent_mappings
    from app.models import ConversationScore as _CS, ConversationCoverage as _CC

    if not settings.ANTHROPIC_API_KEY:
        return {"ok": False, "error": "ANTHROPIC_API_KEY not set"}

    cutoff_utc = (datetime.now(BRASILIA) - timedelta(days=days)).replace(
        hour=0, minute=0, second=0, microsecond=0
    ).astimezone(timezone.utc)

    raw_evs = get_events_since(db, since=cutoff_utc, limit=80000)
    raw_evs = _filter_events_by_channel(raw_evs, canal)
    cam = get_agent_mappings(db)
    groups_orm, phone_learned = _group_events(raw_evs, cam)
    cp  = _real_phone(canal)
    _epoch = datetime.min.replace(tzinfo=timezone.utc)

    from app.services import llm_budget as _llm

    total_scored = 0
    total_skipped = 0
    total_errors  = 0
    capped = False

    for key, evs in groups_orm.items():
        if _real_phone(key) == cp:
            continue
        phone = _real_phone(key)
        agent = (phone_learned.get(key) or cam.get(phone)
                 or phone_learned.get(phone) or "Sem atendente")
        if agent == "Sem atendente":
            continue
        sorted_evs = sorted(
            [e for e in evs if (e.raw_payload or {}).get("type", "").upper()
             not in ("MESSAGE_STATUS", "CONVERSATION_STATUS")],
            key=lambda e: e.received_at or _epoch
        )
        if not sorted_evs:
            continue
        last_event_id = str(sorted_evs[-1].id)
        # Skip só quando JÁ temos nota E cobertura no estado atual.
        cached = db.get(_CS, (phone, last_event_id))
        score_ok = bool(cached and cached.score_version == _SCORE_VERSION)
        cov = db.get(_CC, (phone, last_event_id))
        cov_ok = bool(cov and cov.cov_version == _COV_VERSION)
        if score_ok and cov_ok:
            total_skipped += 1
            continue
        msg_tuples = []
        for ev in sorted_evs:
            _p   = ev.raw_payload or {}
            _txt = _extract_content_preview(_p, max_len=1000) or ""
            _ts  = ev.received_at.astimezone(BRASILIA) if ev.received_at else None
            if _txt:
                msg_tuples.append((_extract_direction(_p), _txt, _ts))
        if not msg_tuples:
            continue
        if not _llm.try_consume(db, feature="avaliacao"):   # teto diário de IA
            capped = True
            break
        try:
            # Uma única chamada devolve nota + produtos ofertados (custo-neutro).
            scored = _call_score_llm(_build_transcript(msg_tuples))
            if not score_ok:
                _upsert_score(db, phone, last_event_id, canal, scored)
            _upsert_coverage(db, phone, last_event_id, canal, agent, scored.get("produtos"))
            total_scored += 1
        except Exception:
            total_errors += 1

    return {
        "ok": True,
        "capped": capped,
        "scored": total_scored,
        "skipped_cached": total_skipped,
        "errors": total_errors,
        "days": days,
    }


@router.post("/dashboard/cron/score-daily", include_in_schema=False)
def cron_score_daily(request: Request, db: Session = Depends(get_db)):
    """Cron endpoint: score all conversations from the last 30 days in batches.

    Protected by the DASHBOARD_PASSWORD token sent in the Authorization header
    as 'Bearer <password>'. Designed to be called once a day without a browser
    session. Processes all batches in one HTTP call (may take several minutes).
    """
    auth = request.headers.get("Authorization", "")
    token = auth.removeprefix("Bearer ").strip()
    _expected = settings.DASHBOARD_PASSWORD or ""
    if not token or not _expected or not hmac.compare_digest(token, _expected):
        return JSONResponse({"error": "unauthorized"}, status_code=401)

    # Desativado por padrão: a avaliação roda pelo agendador interno de domingo.
    # Isto neutraliza qualquer cron externo diário que ainda esteja batendo aqui
    # (era a causa do estouro de custo). Reative com CRON_SCORE_ENABLED=1.
    if str(settings.CRON_SCORE_ENABLED).strip().lower() in ("0", "false", "no", ""):
        db.close()
        return JSONResponse({"ok": True, "disabled": True, "scored": 0,
                             "msg": "cron desativado — avaliação roda no agendador de domingo"})

    canal = _req_canal(request)
    days  = int(request.query_params.get("days", "30"))

    result = run_score_scan(db, canal=canal, days=days)
    db.close()
    if not result.get("ok"):
        return JSONResponse(result, status_code=503)
    return JSONResponse(result)


