@router.get("/dashboard/temas", response_class=HTMLResponse, include_in_schema=False)
def dashboard_temas(request: Request, db: Session = Depends(get_db)):
    access = _get_access(request, db)
    if access is None:
        return _auth_redirect()

    canal = _req_canal(request)
    _dias_raw = request.query_params.get("dias", "7")
    dias = int(_dias_raw) if _dias_raw.isdigit() and int(_dias_raw) in (1, 7, 15, 30) else 7

    _temas_since = (datetime.now(BRASILIA) - timedelta(days=30)).replace(
        hour=0, minute=0, second=0, microsecond=0
    ).astimezone(timezone.utc)
    all_events, _cg, _cpl, client_agent_map, client_name_map = _load_period_pipeline(
        db, canal, _temas_since, 25000
    )
    _pautas_list = _get_pautas(db)
    # Cobertura verificada por IA (varredura de domingo). Chave (phone, last_event_id).
    cov_by_key: dict = {}
    try:
        from app.models import ConversationCoverage as _CCq
        for _r in db.query(_CCq).filter(_CCq.canal == canal, _CCq.cov_version == _COV_VERSION).all():
            cov_by_key[(_r.phone, _r.last_event_id)] = set(_r.produtos or [])
    except Exception:
        cov_by_key = {}
    # Resumo mais recente por telefone (para "conversas recentes" no detalhe v2).
    resumo_by_phone: dict = {}
    try:
        from app.models import ConversationScore as _CSq
        _sc_window = (now_br_tmp := datetime.now(BRASILIA) - timedelta(days=45)).astimezone(timezone.utc)
        for _s in (db.query(_CSq).filter(_CSq.canal == canal, _CSq.scored_at >= _sc_window)
                   .order_by(_CSq.scored_at.asc()).all()):
            resumo_by_phone[_s.phone] = (_s.resumo or "").strip()
    except Exception:
        resumo_by_phone = {}
    db.close()  # release connection before heavy processing

    now_br = datetime.now(BRASILIA)
    if dias == 1:
        period_start = now_br.replace(hour=0, minute=0, second=0, microsecond=0)
    else:
        period_start = (now_br - timedelta(days=dias - 1)).replace(hour=0, minute=0, second=0, microsecond=0)

    period_events = [ev for ev in all_events if ev.received_at and ev.received_at.astimezone(BRASILIA) >= period_start]
    groups, phone_learned = _group_events(period_events, client_agent_map)
    _cp = _real_phone(canal); groups = {k: v for k, v in groups.items() if _real_phone(k) != _cp}

    # ── Pautas: aderência por assessor (mensagens de SAÍDA, janela da pauta) ──
    from urllib.parse import quote as _uq
    is_admin_t = (access or {}).get("role") == "admin"
    pautas_html = ""
    if _pautas_list or is_admin_t:
        # O pipeline cacheado já devolve o agrupamento dos 30d (_cg/_cpl) — reusa.
        groups_all = {k: v for k, v in (_cg or {}).items() if _real_phone(k) != _cp}
        phone_learned_all = _cpl or {}
        _today = now_br.date()
        _all_known = set(AGENT_SEGMENT.keys()) | {
            a for a in (set(client_agent_map.values()) | set(phone_learned_all.values()))
            if a and a != "Sem atendente"
        }

        def _pauta_status(p):
            try:
                di, df = date.fromisoformat(p["inicio"]), date.fromisoformat(p["fim"])
            except (KeyError, TypeError, ValueError):
                return None
            if _today < di:
                return ("agendada", "#5b9bff", di, df)
            if _today > df:
                return ("encerrada", "#5a6a8a", di, df)
            return ("ativa", "#0fa968", di, df)

        _cards = []
        _ranked = sorted(
            (p for p in _pautas_list if _pauta_status(p)),
            key=lambda p: ({"ativa": 0, "agendada": 1, "encerrada": 2}[_pauta_status(p)[0]], p.get("inicio", "")),
        )[:10]

        # Pré-extração 1x (compartilhada entre as pautas): para cada conversa,
        # lista cronológica de (ts BR, direção, texto normalizado, trecho cru).
        conv_cache: dict[str, list] = {}
        agent_of: dict[str, str] = {}
        if _ranked:
            for gkey, evs in groups_all.items():
                _ph = _real_phone(gkey)
                agent_of[gkey] = (phone_learned_all.get(gkey) or client_agent_map.get(_ph)
                                  or phone_learned_all.get(_ph) or "Sem atendente")
                items = []
                for ev in sorted((e for e in evs if e.received_at), key=lambda e: e.received_at):
                    _p = ev.raw_payload or {}
                    txt = _extract_content_preview(_p, max_len=2000) or ""
                    if not txt:
                        continue
                    d_ = (_extract_direction(_p) or "").upper()
                    if d_ not in ("OUT", "IN"):
                        continue
                    items.append((ev.received_at.astimezone(BRASILIA), d_, _opp_norm(txt), txt[:110]))
                conv_cache[gkey] = items

        for p in _ranked:
            st, st_color, d_ini, d_fim = _pauta_status(p)
            kws_norm = [_opp_norm(k) for k in (p.get("keywords") or [])]
            alvo = (p.get("alvo") or "").strip()
            win_start = max(
                datetime(d_ini.year, d_ini.month, d_ini.day, tzinfo=BRASILIA),
                now_br - timedelta(days=30),
            )
            win_end = min(datetime(d_fim.year, d_fim.month, d_fim.day, tzinfo=BRASILIA) + timedelta(days=1), now_br)
            clamped = datetime(d_ini.year, d_ini.month, d_ini.day, tzinfo=BRASILIA) < now_br - timedelta(days=30)

            covered: dict[str, set] = defaultdict(set)
            ativos:  dict[str, set] = defaultdict(set)
            drill: list = []
            puxou = {"OUT": 0, "IN": 0}

            for gkey, items in conv_cache.items():
                ph = _real_phone(gkey)
                agent = agent_of.get(gkey, "Sem atendente")
                if agent == "Sem atendente" or not _user_sees(access, agent):
                    continue
                if alvo and _get_segment(agent) != alvo:
                    continue
                first_dir = None
                any_in_window = False
                for ts, d_, ntxt, snip in items:
                    if not (win_start <= ts < win_end):
                        continue
                    any_in_window = True
                    if not _pauta_match(ntxt, kws_norm):
                        continue
                    if first_dir is None:
                        first_dir = d_
                    if d_ == "OUT":
                        if ph not in covered[agent]:
                            covered[agent].add(ph)
                            drill.append((client_name_map.get(ph, "") or ph, ph, agent, snip))
                        break
                if any_in_window:
                    ativos[agent].add(ph)
                if first_dir:
                    puxou[first_dir] += 1

            targets = sorted(
                (a for a in _all_known if (not alvo or _get_segment(a) == alvo) and _user_sees(access, a)),
                key=lambda a: (-len(covered.get(a, ())), _short_agent_name(a)),
            )
            n_com = sum(1 for a in targets if covered.get(a))
            n_clientes = sum(len(s) for s in covered.values())

            rows = []
            sem_conversa = []
            for a in targets:
                n_cov, n_act = len(covered.get(a, ())), len(ativos.get(a, ()))
                if n_act == 0 and n_cov == 0:
                    sem_conversa.append(_short_agent_name(a))
                    continue
                pct = round(100 * n_cov / n_act) if n_act else 0
                if n_cov == 0:
                    label = '<span style="color:#ef4444;font-weight:700">ainda não abordou</span>'
                else:
                    label = f'<span style="color:#8a96aa">{n_cov} cliente{"s" if n_cov != 1 else ""} · {pct}% das conversas</span>'
                rows.append(
                    '<div style="display:flex;align-items:center;gap:10px;font-size:12px">'
                    f'<span style="width:150px;flex:none;color:#c8d2e8">{html_mod.escape(_short_agent_name(a))}</span>'
                    '<div style="flex:1;height:7px;background:#0b1120;border-radius:4px;overflow:hidden">'
                    f'<div style="width:{min(pct,100)}%;height:100%;background:{"#0fa968" if pct >= 50 else "#eab308"}"></div></div>'
                    f'<span style="width:190px;flex:none;text-align:right">{label}</span></div>'
                )
            tot_puxou = puxou["OUT"] + puxou["IN"]
            puxou_html = (
                f'<span style="font-size:11px;background:#0b1120;border:1px solid #1a2540;border-radius:999px;padding:3px 10px;color:#8a96aa">'
                f'quem puxou o assunto: assessor {round(100*puxou["OUT"]/tot_puxou)}% · cliente {round(100*puxou["IN"]/tot_puxou)}%</span>'
            ) if tot_puxou else ""
            drill_html = ""
            if drill:
                _items = "".join(
                    f'<div style="padding:5px 0;border-bottom:1px solid #131c33;font-size:12px">'
                    f'<a href="/dashboard/conversa?phone={_uq(ph_, safe="")}&canal={_uq(canal, safe="")}" style="color:#0fa968;text-decoration:none;font-weight:600">{html_mod.escape(nm_)}</a>'
                    f' <span style="color:#5a6a8a">· {html_mod.escape(_short_agent_name(ag_))}</span>'
                    f'<div style="color:#8a96aa;margin-top:2px">&ldquo;{html_mod.escape(sn_)}&rdquo;</div></div>'
                    for nm_, ph_, ag_, sn_ in drill[:60]
                )
                drill_html = (
                    f'<details style="margin-top:10px"><summary style="cursor:pointer;font-size:11px;color:#5b9bff">'
                    f'ver clientes abordados ({len(drill)})</summary><div style="margin-top:6px">{_items}</div></details>'
                )
            sem_html = (
                f'<div style="font-size:11px;color:#5a6a8a;margin-top:8px">sem conversas na vigência: {html_mod.escape(", ".join(sem_conversa[:15]))}'
                + (f" +{len(sem_conversa)-15}" if len(sem_conversa) > 15 else "") + "</div>"
            ) if sem_conversa else ""
            _pid = str(p.get("id") or "")
            del_btn = (
                f'<button onclick="pautaExcluir(\'{_pid}\')" title="Excluir pauta" '
                'style="background:transparent;border:none;color:#5a6a8a;cursor:pointer;font-size:13px">&#10005;</button>'
            ) if (is_admin_t and _re.fullmatch(r"[0-9a-f]{2,40}", _pid)) else ""
            clamp_note = ' <span style="color:#5a6a8a">(análise: últimos 30 dias)</span>' if clamped else ""
            _cards.append(
                f'<div class="card" style="margin-bottom:14px{";opacity:.6" if st == "encerrada" else ""}">'
                '<div style="display:flex;align-items:baseline;gap:10px;flex-wrap:wrap;margin-bottom:2px">'
                f'<span style="font-size:14px;font-weight:700;color:#e8ecf1">{html_mod.escape(p.get("nome", ""))}</span>'
                f'<span style="font-size:10px;font-weight:700;letter-spacing:1px;color:{st_color};border:1px solid {st_color}55;border-radius:999px;padding:2px 9px">{st.upper()}</span>'
                f'<span style="font-size:11px;color:#5a6a8a">{d_ini.strftime("%d/%m")} &ndash; {d_fim.strftime("%d/%m")} · alvo: {html_mod.escape(alvo) if alvo else "todas as mesas"}{clamp_note}</span>'
                f'<span style="margin-left:auto;display:flex;gap:8px;align-items:center">{puxou_html}{del_btn}</span></div>'
                f'<div style="font-size:12px;color:#8a96aa;margin-bottom:10px"><b style="color:#0fa968">{n_com}</b> de {len(targets)} assessores já levaram o tema · <b>{n_clientes}</b> clientes abordados</div>'
                f'<div style="display:flex;flex-direction:column;gap:5px">{"".join(rows) or "<span style=\'font-size:12px;color:#5a6a8a\'>nenhum assessor com conversa na vigência</span>"}</div>'
                f'{sem_html}{drill_html}</div>'
            )

        _form_html = ""
        if is_admin_t:
            _opts = '<option value="">Todas as mesas</option>' + "".join(
                f'<option value="{html_mod.escape(s)}">{html_mod.escape(s)}</option>' for s in _all_segments()
            )
            _hoje = _today.isoformat()
            _fim_default = (_today + timedelta(days=13)).isoformat()
            _inp = "background:#0b1120;border:1px solid #1a2540;border-radius:6px;color:#e8ecf1;padding:7px 10px;font-size:12px"
            _form_html = (
                '<details style="margin-bottom:14px"><summary style="cursor:pointer;font-size:12px;color:#0fa968;font-weight:700">+ Nova pauta</summary>'
                '<div class="card" style="margin-top:10px;display:flex;flex-direction:column;gap:8px">'
                f'<input id="pt-nome" placeholder="Nome da pauta (ex.: Consórcio / aquisição de bens)" style="{_inp}">'
                f'<input id="pt-kws" placeholder="Palavras-chave separadas por vírgula (ex.: consórcio, carta de crédito, contemplação)" style="{_inp}">'
                '<div style="display:flex;gap:8px;flex-wrap:wrap">'
                f'<input id="pt-ini" type="date" value="{_hoje}" style="{_inp}">'
                f'<input id="pt-fim" type="date" value="{_fim_default}" style="{_inp}">'
                f'<select id="pt-alvo" style="{_inp}">{_opts}</select>'
                '<button onclick="pautaCriar()" style="background:#0fa968;border:none;border-radius:6px;color:#04150c;font-weight:700;font-size:12px;padding:7px 16px;cursor:pointer">Criar pauta</button>'
                '</div><div style="font-size:11px;color:#5a6a8a">A aderência conta apenas mensagens <b>enviadas pelo assessor</b> dentro da vigência (sem acento/maiúsculas não importam). Sem custo de IA.</div>'
                '</div></details>'
            )

        _pauta_js = """<script>
function pautaCriar(){
  var b={nome:document.getElementById('pt-nome').value,keywords:document.getElementById('pt-kws').value,
         inicio:document.getElementById('pt-ini').value,fim:document.getElementById('pt-fim').value,
         alvo:document.getElementById('pt-alvo').value};
  fetch('/dashboard/pautas',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(b)})
    .then(function(r){return r.json();}).then(function(d){if(d.ok){location.reload();}else{alert(d.error||'erro');}});
}
function pautaExcluir(id){
  if(!confirm('Excluir esta pauta?'))return;
  fetch('/dashboard/pautas/excluir',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({id:id})})
    .then(function(){location.reload();});
}
</script>"""
        _empty = (
            '<p style="font-size:12px;color:#5a6a8a;margin:0 0 4px">Nenhuma pauta cadastrada. '
            'Crie a primeira em <b>+ Nova pauta</b> — ex.: &ldquo;Consórcio&rdquo; ou &ldquo;Renda Variável&rdquo;.</p>'
        ) if (is_admin_t and not _cards) else ""
        pautas_html = (
            '<div style="margin-bottom:24px">'
            '<div style="display:flex;align-items:center;gap:10px;margin-bottom:10px">'
            '<span style="width:8px;height:8px;border-radius:50%;background:#d4af37;display:inline-block"></span>'
            '<h2 style="margin:0;font-size:15px">Pautas — o time está levando o tema aos clientes?</h2></div>'
            + _empty + _form_html + "".join(_cards) + _pauta_js + "</div>"
        ) if (_cards or is_admin_t) else ""

    # ── Build topic × agent matrix (COBERTURA: só mensagens do ASSESSOR) ──────
    # topic_data[topic_id][agent] = clientes a quem o ASSESSOR ofereceu o tema.
    # Conta apenas mensagens OUT — o objetivo é "o assessor levou o produto?",
    # não "o cliente perguntou". Texto normalizado (sem acento) p/ casar bem.
    topic_kws_norm = {tid: [_opp_norm(k) for k in kws] for tid, _tl, _tc, kws in TOPIC_RULES}
    topic_data: dict[str, dict[str, set]] = {tid: defaultdict(set) for tid, *_ in TOPIC_RULES}
    topic_clients: dict[str, list] = {tid: [] for tid, *_ in TOPIC_RULES}
    _seen_topic_client: dict[str, set] = {tid: set() for tid, *_ in TOPIC_RULES}
    agent_clients: dict[str, set] = defaultdict(set)   # clientes atendidos no período

    def _first_topic_kw(text_norm, kws_norm):
        for kw in kws_norm:
            if not kw:
                continue
            if " " in kw or len(kw) > 5:
                if kw in text_norm:
                    return kw
            elif _re.search(r"(?<![a-z0-9])" + _re.escape(kw) + r"(?![a-z0-9])", text_norm):
                return kw
        return None

    _epoch_t = datetime.min.replace(tzinfo=timezone.utc)
    n_conv_ia = 0
    n_conv_kw = 0
    last_ts_by_phone: dict = {}   # última atividade por cliente (p/ "conversas recentes")
    for client_num, evs in groups.items():
        ph = _real_phone(client_num)
        agent = phone_learned.get(client_num) or client_agent_map.get(ph) or phone_learned.get(ph) or "Sem atendente"
        if agent == "Sem atendente" or not _user_sees(access, agent):
            continue
        agent_clients[agent].add(ph)
        # last_event_id (não-status) p/ casar com a cobertura verificada por IA.
        nonstatus = sorted(
            (e for e in evs if (e.raw_payload or {}).get("type", "").upper()
             not in ("MESSAGE_STATUS", "CONVERSATION_STATUS") and e.received_at),
            key=lambda e: e.received_at,
        )
        leid = str(nonstatus[-1].id) if nonstatus else ""
        if nonstatus:
            last_ts_by_phone[ph] = nonstatus[-1].received_at
        ai_prods = cov_by_key.get((ph, leid)) if leid else None

        if ai_prods is not None:
            # IA é autoritativa para este estado da conversa.
            n_conv_ia += 1
            for tid in ai_prods:
                if tid in _seen_topic_client and ph not in _seen_topic_client[tid]:
                    topic_data[tid][agent].add(ph)
                    _seen_topic_client[tid].add(ph)
                    topic_clients[tid].append({
                        "phone": ph, "name": client_name_map.get(ph, ""), "agent": agent, "kw": "✓ IA"
                    })
        else:
            # Fallback por palavra-chave (até a varredura de domingo classificar).
            out_parts = []
            for ev in evs:
                _p = ev.raw_payload or {}
                if (_extract_direction(_p) or "").upper() != "OUT":
                    continue
                t = _extract_content_preview(_p, max_len=2000) or ""
                if t:
                    out_parts.append(t)
            if not out_parts:
                continue
            n_conv_kw += 1
            out_norm = _opp_norm(" ".join(out_parts))
            for tid, tlabel, tcolor, keywords in TOPIC_RULES:
                if ph in _seen_topic_client[tid]:
                    continue
                mk = _first_topic_kw(out_norm, topic_kws_norm[tid])
                if mk:
                    topic_data[tid][agent].add(ph)
                    _seen_topic_client[tid].add(ph)
                    topic_clients[tid].append({
                        "phone": ph, "name": client_name_map.get(ph, ""), "agent": agent, "kw": mk
                    })

    # ── Known agents list ────────────────────────────────────────────────────
    known_agents = [a for a in AGENT_SEGMENT]
    # Also include any agents found via phone_learned not in AGENT_SEGMENT
    extra_agents = set()
    for tid in topic_data:
        for ag in topic_data[tid]:
            if ag not in AGENT_SEGMENT and ag != "Sem atendente":
                extra_agents.add(ag)
    all_agents = known_agents + sorted(extra_agents)

    # Filter out agents with zero activity across all topics
    active_agents = [ag for ag in all_agents if any(topic_data[tid].get(ag) for tid in topic_data)]

    # Temas v2: o detalhe (master-detail) substitui a tabela/heatmap antiga.
    active_topics = [(tid, tlabel, tcolor, kws) for tid, tlabel, tcolor, kws in TOPIC_RULES if _seen_topic_client[tid]]
    _mx = max((len(_seen_topic_client[tid]) for tid, *_ in active_topics), default=1)
    _base_qs = f"canal={canal}"
    _period_label = "Hoje" if dias == 1 else f"Últimos {dias} dias"

    # ── COBERTURA DA PRATELEIRA — score por assessor + lacunas do time ───────
    shelf = [(tid, tlabel, tcolor) for tid, tlabel, tcolor, _ in TOPIC_RULES]
    shelf_n = len(shelf) or 1

    def _offered(a):
        return [tid for tid, _tl, _tc in shelf if topic_data[tid].get(a)]

    # Assessores ATIVOS no período (tiveram conversa), do pior pro melhor coberto.
    # Ranking do MAIS pro MENOS coberto (melhor no topo); empata por nº de clientes.
    cov_agents = sorted(
        agent_clients.keys(),
        key=lambda a: (-len(_offered(a)), -len(agent_clients[a]), _short_agent_name(a)),
    )
    n_adv = len(cov_agents)
    team_offer = {tid: sum(1 for a in cov_agents if topic_data[tid].get(a)) for tid, _tl, _tc in shelf}

    def _cov_color(pct):
        return "#ef4444" if pct < 30 else ("#eab308" if pct < 60 else "#0fa968")

    cov_avg = (sum(len(_offered(a)) for a in cov_agents) / n_adv) if n_adv else 0
    gap_threshold = max(1, round(n_adv * 0.25))
    n_neglected = sum(1 for tid, _tl, _tc in shelf if team_offer[tid] <= gap_threshold)
    # "Mais estreito" = menor cobertura (independe da ordem do ranking).
    narrowest = min(cov_agents, key=lambda a: (len(_offered(a)), -len(agent_clients[a]))) if cov_agents else None
    is_admin_v2 = (access or {}).get("role") == "admin"

    # ── helpers v2 ───────────────────────────────────────────────────────────
    def _v2_status(p):
        if p >= 70:
            return ("Amplo", "#22c66e", "rgba(34,198,110,0.12)", "rgba(34,198,110,0.35)")
        if p >= 45:
            return ("Moderado", "#f2b007", "rgba(242,176,7,0.12)", "rgba(242,176,7,0.35)")
        return ("Estreito", "#ef5a6a", "rgba(239,90,106,0.12)", "rgba(239,90,106,0.35)")

    def _v2_rel(ts):
        if not ts:
            return ""
        s = (now_br - ts.astimezone(BRASILIA)).total_seconds()
        if s < 3600:
            return f"há {max(1, int(s // 60))} min"
        if s < 86400:
            return f"há {int(s // 3600)}h"
        d = int(s // 86400)
        return "ontem" if d == 1 else f"há {d} dias"

    # clientes/conversas por assessor (a partir do drill já calculado)
    convos_by_agent: dict = defaultdict(list)
    for _tid, _tl, _tc in shelf:
        for _c in topic_clients[_tid]:
            convos_by_agent[(_c["agent"] or "").lower()].append((_tid, _tl, _tc, _c["phone"], _c["name"]))

    JM = "'JetBrains Mono'"   # evita escapar aspas no f-string

    list_rows = []
    panels = []
    for idx, a in enumerate(cov_agents):
        aid = (_re.sub(r"[^a-z0-9]+", "-", _opp_norm(a)).strip("-") or "a") + f"-{idx}"
        offered = _offered(a)
        n_off = len(offered)
        pct = round(100 * n_off / shelf_n)
        slabel, scol, sbg, sbord = _v2_status(pct)
        clients = len(agent_clients[a])
        cli_lbl = f"{clients} cliente" + ("s" if clients != 1 else "")
        sel = (idx == 0)
        nm = html_mod.escape(_short_agent_name(a))

        list_rows.append(
            f'<div class="advrow" data-id="{aid}" data-selbar="{scol}" onclick="selAdv(\'{aid}\')" '
            f'style="display:grid;grid-template-columns:auto 1fr auto;align-items:center;gap:12px;padding:11px 12px;border-radius:10px;'
            f'border-left:3px solid {scol if sel else "transparent"};background:{"rgba(34,198,110,0.1)" if sel else "transparent"};margin-bottom:3px;">'
            f'<span style="width:8px;height:8px;border-radius:3px;background:{scol};flex:none;"></span>'
            f'<div style="min-width:0;"><div class="advname" style="font-size:13.5px;font-weight:600;color:{"#ffffff" if sel else "#d2d8e4"};white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">{nm}</div>'
            f'<div style="height:5px;border-radius:3px;background:#161d2e;overflow:hidden;margin-top:6px;"><div style="height:100%;border-radius:3px;width:{pct}%;background:{scol};"></div></div></div>'
            f'<div style="text-align:right;white-space:nowrap;"><div style="font-family:{JM};font-weight:700;font-size:12.5px;color:{scol};">{n_off}/{shelf_n}</div>'
            f'<div style="font-size:10.5px;color:#6a7589;font-family:{JM};margin-top:2px;">{cli_lbl}</div></div></div>'
        )

        # breakdown (produtos que oferece) + mais/menos + nunca ofereceu
        bd = sorted(((len(topic_data[tid].get(a, ())), tid, tl, tc) for tid, tl, tc in shelf if topic_data[tid].get(a)), reverse=True)
        bd_tot = sum(c for c, *_ in bd)
        maxv = bd[0][0] if bd else 1
        conc = ""
        if bd and n_off <= 3 and bd_tot:
            conc = f'<div style="font-size:12.5px;color:#9aa3b8;margin-top:6px;display:inline-block;background:rgba(255,255,255,0.04);border-radius:7px;padding:5px 11px;">concentra {round(100*bd[0][0]/bd_tot)}% em {html_mod.escape(bd[0][2])}</div>'
        bd_html = "".join(
            f'<div style="display:grid;grid-template-columns:104px 1fr 24px;align-items:center;gap:10px;">'
            f'<span style="font-size:12px;color:#b8c0d0;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">{html_mod.escape(tl)}</span>'
            f'<div style="height:7px;border-radius:4px;background:#161d2e;overflow:hidden;"><div style="height:100%;border-radius:4px;width:{round(c/maxv*100)}%;background:{tc};"></div></div>'
            f'<span style="font-family:{JM};font-size:12px;font-weight:600;color:#e8edf5;text-align:right;">{c}</span></div>'
            for c, tid, tl, tc in bd
        ) or '<div style="font-size:12.5px;color:#6a7589;font-style:italic;">Nenhum produto levado ao cliente neste período.</div>'

        gaps = [tl for tid, tl, tc in shelf if tid not in set(offered)]
        if gaps:
            chips = "".join(
                f'<span style="font-size:11.5px;font-weight:500;color:#ff8a94;background:rgba(239,90,106,0.1);border:1px solid rgba(239,90,106,0.25);border-radius:6px;padding:3px 9px;">{html_mod.escape(g)}</span>'
                for g in gaps[:9]
            )
            if len(gaps) > 9:
                chips += f'<span style="font-size:11.5px;font-weight:500;color:#6a7589;background:rgba(255,255,255,0.04);border:1px solid rgba(255,255,255,0.08);border-radius:6px;padding:3px 9px;">+{len(gaps)-9}</span>'
        else:
            chips = '<span style="font-size:12px;font-weight:500;color:#3ddc84;">Cobre toda a prateleira ✓</span>'

        # mais/menos oferece
        pair = ""
        if len(bd) >= 2:
            top, bot = bd[0], bd[-1]
            pair = (
                '<div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-top:22px;">'
                f'<div style="background:rgba(34,198,110,0.08);border:1px solid rgba(34,198,110,0.22);border-radius:11px;padding:14px 16px;"><div style="font-size:10px;font-weight:700;letter-spacing:0.14em;color:#3ddc84;text-transform:uppercase;margin-bottom:8px;">▲ Mais oferece</div><div style="font-size:16px;font-weight:600;color:#e8edf5;line-height:1.15;">{html_mod.escape(top[2])}</div><div style="font-size:12px;color:#8893a8;font-family:{JM};margin-top:4px;">{top[0]} cliente{"s" if top[0]!=1 else ""}</div></div>'
                f'<div style="background:rgba(242,176,7,0.07);border:1px solid rgba(242,176,7,0.22);border-radius:11px;padding:14px 16px;"><div style="font-size:10px;font-weight:700;letter-spacing:0.14em;color:#f2b007;text-transform:uppercase;margin-bottom:8px;">▼ Menos oferece</div><div style="font-size:16px;font-weight:600;color:#e8edf5;line-height:1.15;">{html_mod.escape(bot[2])}</div><div style="font-size:12px;color:#8893a8;font-family:{JM};margin-top:4px;">{bot[0]} cliente{"s" if bot[0]!=1 else ""}</div></div>'
                '</div>'
            )
        elif len(bd) == 1:
            top = bd[0]
            pair = (f'<div style="background:rgba(34,198,110,0.08);border:1px solid rgba(34,198,110,0.22);border-radius:11px;padding:14px 16px;margin-top:22px;"><div style="font-size:10px;font-weight:700;letter-spacing:0.14em;color:#3ddc84;text-transform:uppercase;margin-bottom:8px;">Oferece só</div><div style="font-size:16px;font-weight:600;color:#e8edf5;">{html_mod.escape(top[2])} · <span style="color:#8893a8;font-family:{JM};font-size:13px;">{top[0]} cliente{"s" if top[0]!=1 else ""}</span></div></div>')

        # conversas recentes (reais)
        cv = sorted(convos_by_agent.get(a.lower(), []), key=lambda x: last_ts_by_phone.get(x[3]) or _epoch_t, reverse=True)[:4]
        convos_html = "".join(
            f'<div style="display:flex;gap:11px;align-items:flex-start;background:#0e1422;border:1px solid rgba(255,255,255,0.06);border-radius:10px;padding:11px 13px;">'
            f'<span style="width:6px;height:6px;border-radius:50%;background:{tc};margin-top:6px;flex:none;"></span>'
            f'<div style="flex:1;min-width:0;"><div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-bottom:3px;">'
            f'<span style="font-size:12.5px;font-weight:600;color:#e8edf5;">{html_mod.escape(name or phone)}</span>'
            f'<span style="font-size:10.5px;font-weight:600;color:{tc};background:rgba(255,255,255,0.05);border-radius:5px;padding:2px 7px;">{html_mod.escape(tl)}</span>'
            f'<span style="font-size:11px;color:#5b6577;margin-left:auto;font-family:{JM};">{_v2_rel(last_ts_by_phone.get(phone))}</span></div>'
            + (f'<div style="font-size:12.5px;color:#9aa3b8;line-height:1.45;">{html_mod.escape((resumo_by_phone.get(phone) or "")[:120])}</div>' if resumo_by_phone.get(phone) else "")
            + '</div></div>'
            for tid, tl, tc, phone, name in cv
        ) or '<div style="font-size:12.5px;color:#6a7589;font-style:italic;">Sem conversas com produto identificado no período.</div>'

        ring_deg = round(n_off / shelf_n * 360)
        panels.append(
            f'<div class="advdetail{" on" if sel else ""}" id="adv-{aid}">'
            '<div style="display:flex;align-items:flex-start;justify-content:space-between;gap:24px;">'
            f'<div><div style="display:flex;align-items:center;gap:11px;"><h2 class="spaced" style="font-weight:700;font-size:24px;margin:0;letter-spacing:-0.01em;">{nm}</h2>'
            f'<span style="font-size:11px;font-weight:700;letter-spacing:0.08em;text-transform:uppercase;color:{scol};background:{sbg};border:1px solid {sbord};border-radius:7px;padding:4px 10px;">{slabel}</span></div>'
            f'<div style="font-size:13px;color:#8893a8;margin-top:7px;">{cli_lbl} atendido{"s" if clients!=1 else ""} no período · {n_off}/{shelf_n} produtos cobertos</div>{conc}</div>'
            f'<div style="position:relative;width:96px;height:96px;flex:none;border-radius:50%;background:conic-gradient({scol} {ring_deg}deg, #1a2336 0);display:flex;align-items:center;justify-content:center;">'
            f'<div style="position:absolute;inset:9px;border-radius:50%;background:#0b101c;display:flex;flex-direction:column;align-items:center;justify-content:center;"><span style="font-family:{JM};font-weight:700;font-size:24px;color:{scol};line-height:1;">{n_off}</span><span style="font-size:10px;color:#6a7589;font-family:{JM};margin-top:2px;">de {shelf_n}</span></div></div></div>'
            + pair +
            '<div style="display:grid;grid-template-columns:1fr 1fr;gap:30px;margin-top:24px;">'
            '<div><div class="spaced" style="font-size:11px;font-weight:600;letter-spacing:0.16em;color:#7a8499;text-transform:uppercase;margin-bottom:14px;">Produtos que oferece</div>'
            f'<div style="display:flex;flex-direction:column;gap:11px;">{bd_html}</div>'
            '<div class="spaced" style="font-size:11px;font-weight:600;letter-spacing:0.16em;color:#7a8499;text-transform:uppercase;margin:22px 0 11px;">Nunca ofereceu</div>'
            f'<div style="display:flex;flex-wrap:wrap;gap:7px;">{chips}</div></div>'
            '<div><div class="spaced" style="font-size:11px;font-weight:600;letter-spacing:0.16em;color:#7a8499;text-transform:uppercase;margin-bottom:14px;">Conversas recentes</div>'
            f'<div style="display:flex;flex-direction:column;gap:9px;">{convos_html}</div></div>'
            '</div></div>'
        )

    list_html = "".join(list_rows) or '<div style="font-size:12.5px;color:#6a7589;padding:24px;text-align:center;">Nenhum assessor com conversa no período.</div>'
    panels_html = "".join(panels) or '<div style="font-size:13px;color:#6a7589;">Sem dados no período.</div>'

    # ── Lacunas do time ──────────────────────────────────────────────────────
    team_gaps = sorted(((tid, tl, tc) for tid, tl, tc in shelf), key=lambda s: team_offer[s[0]])
    gap_rows = ""
    for tid, tl, tc in team_gaps[:6]:
        no = team_offer[tid]
        gp = round(100 * no / n_adv) if n_adv else 0
        gcol = "#ef5a6a" if no <= 3 else ("#f2b007" if no <= 5 else "#22c66e")
        gap_rows += (
            '<div style="display:grid;grid-template-columns:180px 1fr 150px;align-items:center;gap:18px;">'
            f'<span style="font-size:13.5px;font-weight:500;color:#d2d8e4;">{html_mod.escape(tl)}</span>'
            f'<div style="height:10px;border-radius:5px;background:#161d2e;overflow:hidden;"><div style="height:100%;border-radius:5px;width:{max(gp,2)}%;background:{gcol};"></div></div>'
            f'<span style="font-size:12.5px;color:#8893a8;text-align:right;font-family:{JM};"><span style="color:{gcol};font-weight:600;">{no}</span> de {n_adv} assessores</span></div>'
        )

    # ── Matriz (assessor × produto) ──────────────────────────────────────────
    col_max = {tid: max((len(topic_data[tid].get(a, ())) for a in cov_agents), default=0) or 1 for tid, *_ in active_topics}
    mh = "".join(
        f'<th style="padding:0 4px 12px;font-size:10px;font-weight:600;letter-spacing:0.06em;color:#7a8499;text-transform:uppercase;text-align:center;white-space:nowrap;" class="spaced"><span style="display:inline-flex;align-items:center;gap:5px;"><span style="width:7px;height:7px;border-radius:50%;background:{tc};"></span>{html_mod.escape(tl)}</span></th>'
        for tid, tl, tc, _ in active_topics
    )
    matrix_adv = sorted(cov_agents, key=lambda a: -sum(len(topic_data[tid].get(a, ())) for tid, *_ in active_topics))
    mrows = ""
    for a in matrix_adv:
        dotc = _v2_status(round(100 * len(_offered(a)) / shelf_n))[1]
        cells = ""
        for tid, tl, tc, _ in active_topics:
            v = len(topic_data[tid].get(a, ()))
            if v:
                alpha = 0.08 + (v / col_max[tid]) * 0.2
                cells += f'<td style="text-align:center;padding:9px 4px;"><span style="display:inline-block;min-width:34px;padding:5px 0;border-radius:7px;font-family:{JM};font-size:13px;font-weight:600;color:#e8edf5;background:rgba(34,198,110,{alpha:.3f});">{v}</span></td>'
            else:
                cells += f'<td style="text-align:center;padding:9px 4px;"><span style="font-family:{JM};font-size:13px;color:#3f4861;">—</span></td>'
        mrows += (
            '<tr style="border-top:1px solid rgba(255,255,255,0.05);">'
            f'<td style="padding:11px 14px 11px 6px;font-size:13px;font-weight:500;white-space:nowrap;position:sticky;left:0;background:#0b101c;"><span style="display:inline-flex;align-items:center;gap:8px;"><span style="width:6px;height:6px;border-radius:50%;background:{dotc};"></span>{html_mod.escape(_short_agent_name(a))}</span></td>{cells}</tr>'
        )
    mtot = "".join(
        f'<td style="text-align:center;padding:14px 4px 4px;"><span style="display:inline-block;min-width:38px;padding:6px 0;border-radius:7px;font-family:{JM};font-size:14px;font-weight:700;color:#3ddc84;background:rgba(34,198,110,0.14);">{len(_seen_topic_client[tid])}</span></td>'
        for tid, tl, tc, _ in active_topics
    )

    # ── Período tabs + canal selector + sidebar ──────────────────────────────
    period_tabs = "".join(
        f'<a href="?{_base_qs}&dias={d}" style="text-decoration:none;padding:6px 14px;border-radius:8px;font-size:12.5px;font-weight:600;'
        f'border:1px solid {"rgba(34,198,110,0.4)" if d==dias else "rgba(255,255,255,0.08)"};background:{"rgba(34,198,110,0.14)" if d==dias else "#0e1422"};'
        f'color:{"#3ddc84" if d==dias else "#9aa3b8"};">{lbl}</a>'
        for d, lbl in [(1, "Hoje"), (7, "7 dias"), (15, "15 dias"), (30, "30 dias")]
    )
    canal_opts = ""
    for ch_num, ch_label in sorted(COMPANY_CHANNELS_MAP.items(), key=lambda x: x[1]):
        _selm = " selected" if canal == ch_num else ""
        canal_opts += f'<option value="{ch_num}"{_selm}>{html_mod.escape(ch_label)} ({ch_num[-4:]})</option>'

    def _v2nav(label, href, active=False):
        if active:
            return (f'<a href="{href}" style="text-decoration:none;padding:9px 12px;border-radius:8px;font-size:13px;font-weight:600;color:#062012;'
                    'background:linear-gradient(135deg,#22c66e,#16a85c);display:flex;align-items:center;gap:9px;box-shadow:0 4px 14px rgba(34,198,110,0.28);">'
                    f'<span style="width:5px;height:5px;border-radius:50%;background:#062012;"></span>{label}</a>')
        return f'<a href="{href}" class="v2nav" style="text-decoration:none;padding:8px 12px;border-radius:8px;font-size:13px;font-weight:500;color:#9aa3b8;display:block;">{label}</a>'

    _cq = f"?canal={canal}"
    admin_nav = ""
    if is_admin_v2:
        admin_nav = (
            '<div class="spaced" style="font-size:9.5px;font-weight:600;letter-spacing:0.22em;color:#4a5369;padding:0 6px 10px;">ADMIN</div>'
            '<nav style="display:flex;flex-direction:column;gap:1px;">'
            + _v2nav("Acessos", "/dashboard/acessos")
            + _v2nav("Diagnóstico", "/dashboard/diagnostico" + _cq) + '</nav>'
        )
    sidebar_html = (
        '<aside style="width:248px;flex:none;background:#0a0e1a;border-right:1px solid rgba(255,255,255,0.06);display:flex;flex-direction:column;padding:26px 18px;position:sticky;top:0;height:100vh;overflow-y:auto;">'
        '<div style="display:flex;align-items:center;gap:11px;padding:0 6px 4px;">'
        '<div style="width:34px;height:34px;border-radius:9px;background:linear-gradient(135deg,#22c66e,#0e8a4a);display:flex;align-items:center;justify-content:center;font-weight:700;font-size:18px;color:#06140c;" class="spaced">A</div>'
        '<div style="line-height:1.05;"><div class="spaced" style="font-weight:700;font-size:14px;letter-spacing:0.04em;">ALTOVALOR</div><div style="font-size:9.5px;letter-spacing:0.32em;color:#6a7589;">INVESTIDORES</div></div></div>'
        '<div class="spaced" style="font-weight:600;font-size:10px;letter-spacing:0.4em;color:#3f4861;padding:14px 6px 22px;">GRAMPO</div>'
        '<div class="spaced" style="font-size:9.5px;font-weight:600;letter-spacing:0.22em;color:#4a5369;padding:0 6px 10px;">MONITORAMENTO</div>'
        '<nav style="display:flex;flex-direction:column;gap:1px;margin-bottom:22px;">'
        + _v2nav("Visão geral", "/dashboard/overview" + _cq) + _v2nav("Conversas", "/dashboard" + _cq)
        + _v2nav("Alertas", "/dashboard/alertas" + _cq) + _v2nav("Sem resposta", "/dashboard/sem-resposta" + _cq)
        + _v2nav("Oportunidades", "/dashboard/oportunidades" + _cq) + _v2nav("Agentes", "/dashboard/agentes" + _cq) + '</nav>'
        '<div class="spaced" style="font-size:9.5px;font-weight:600;letter-spacing:0.22em;color:#4a5369;padding:0 6px 10px;">ANÁLISE</div>'
        '<nav style="display:flex;flex-direction:column;gap:1px;margin-bottom:22px;">'
        + _v2nav("Temas", "/dashboard/temas" + _cq, active=True) + _v2nav("Clientes", "/dashboard/clientes" + _cq)
        + _v2nav("Avaliação agentes", "/dashboard/avaliacao-agentes" + _cq) + _v2nav("Evolução", "/dashboard/evolucao" + _cq)
        + _v2nav("Mensagens iniciais", "/dashboard/mensagens" + _cq) + '</nav>'
        + admin_nav +
        '<div style="margin-top:auto;display:flex;align-items:center;gap:11px;padding:12px 8px 0;border-top:1px solid rgba(255,255,255,0.06);">'
        '<div class="spaced" style="width:32px;height:32px;border-radius:50%;background:#13301f;border:1px solid #1f6b40;display:flex;align-items:center;justify-content:center;font-size:11px;font-weight:700;color:#3ddc84;">AV</div>'
        '<div style="line-height:1.15;"><div style="font-size:13px;font-weight:600;">Gestor</div><a href="/dashboard/logout" style="font-size:11px;color:#6a7589;text-decoration:none;">Sair</a></div></div></aside>'
    )

    _avg_col = _v2_status(round(100 * cov_avg / shelf_n))[1] if n_adv else "#3ddc84"
    metrics_html = (
        '<div style="display:flex;align-items:stretch;background:#0e1422;border:1px solid rgba(255,255,255,0.07);border-radius:14px;overflow:hidden;margin-bottom:16px;flex-wrap:wrap;">'
        f'<div style="flex:1;min-width:170px;padding:18px 24px;border-right:1px solid rgba(255,255,255,0.06);border-top:3px solid #22c66e;"><div style="display:flex;align-items:baseline;gap:5px;"><span style="font-family:{JM};font-weight:700;font-size:30px;color:{_avg_col};">{cov_avg:.1f}</span><span style="font-family:{JM};font-size:14px;color:#5b6577;">/ {shelf_n}</span></div><div class="spaced" style="font-size:10.5px;font-weight:600;letter-spacing:0.12em;color:#8893a8;text-transform:uppercase;margin-top:5px;">Cobertura média / assessor</div></div>'
        f'<div style="flex:1;min-width:170px;padding:18px 24px;border-right:1px solid rgba(255,255,255,0.06);border-top:3px solid #ef5a6a;"><div style="font-family:{JM};font-weight:700;font-size:30px;color:#ff7b87;">{n_neglected}</div><div class="spaced" style="font-size:10.5px;font-weight:600;letter-spacing:0.12em;color:#8893a8;text-transform:uppercase;margin-top:5px;">Produtos negligenciados</div></div>'
        f'<div style="flex:1.3;min-width:190px;padding:18px 24px;border-right:1px solid rgba(255,255,255,0.06);border-top:3px solid #f2b007;"><div class="spaced" style="font-weight:700;font-size:20px;color:#f2b007;line-height:1.15;">{html_mod.escape(_short_agent_name(narrowest)) if narrowest else "—"}</div><div class="spaced" style="font-size:10.5px;font-weight:600;letter-spacing:0.12em;color:#8893a8;text-transform:uppercase;margin-top:6px;">Assessor mais estreito</div></div>'
        f'<div style="flex:1.2;min-width:170px;padding:18px 24px;border-top:3px solid #38bdf8;"><div style="font-family:{JM};font-weight:700;font-size:30px;color:#7ccef5;">{n_conv_ia}</div><div class="spaced" style="font-size:10.5px;font-weight:600;letter-spacing:0.12em;color:#8893a8;text-transform:uppercase;margin-top:5px;">Conversas verificadas · IA</div></div>'
        '</div>'
    )

    _src_note = (f'<span style="color:#3ddc84;">✓ {n_conv_ia} conversas verificadas por IA</span>'
                 + (f' · {n_conv_kw} por palavra-chave' if n_conv_kw else '')) if n_conv_ia else 'Detecção por palavra-chave — a IA classifica na varredura de domingo.'
    split_html = (
        '<div style="display:grid;grid-template-columns:368px 1fr;gap:16px;margin-bottom:16px;align-items:start;">'
        '<div class="v2card" style="overflow:hidden;">'
        '<div style="padding:18px 20px 14px;border-bottom:1px solid rgba(255,255,255,0.06);">'
        '<div style="display:flex;align-items:center;gap:9px;"><span style="width:7px;height:7px;border-radius:50%;background:#22c66e;"></span><h2 class="spaced" style="font-weight:600;font-size:15px;margin:0;">Cobertura da prateleira</h2></div>'
        f'<div style="font-size:11.5px;color:#6a7589;margin-top:5px;">do mais pro menos coberto · {_period_label.lower()}</div></div>'
        f'<div style="max-height:660px;overflow-y:auto;padding:8px;">{list_html}</div></div>'
        f'<div class="v2card" style="padding:26px 28px;position:sticky;top:18px;">{panels_html}'
        f'<div style="font-size:11px;color:#5b6577;margin-top:20px;border-top:1px solid rgba(255,255,255,0.06);padding-top:12px;">Conta só quando o <b style="color:#9aa3b8;">assessor</b> leva o produto ao cliente. {_src_note}</div>'
        '</div></div>'
    )

    lacunas_html = (
        '<div class="v2card" style="padding:24px 26px;margin-bottom:16px;">'
        '<div style="display:flex;align-items:center;gap:10px;margin-bottom:4px;"><span style="font-size:15px;">⚠️</span><h2 class="spaced" style="font-weight:600;font-size:18px;margin:0;">Lacunas do time</h2><span style="font-size:14px;color:#6a7589;font-weight:400;">produtos que quase ninguém oferece</span></div>'
        f'<div style="display:flex;flex-direction:column;gap:11px;margin-top:20px;">{gap_rows}</div></div>'
    ) if (gap_rows and n_adv) else ""

    matriz_html = (
        '<div class="v2card" style="padding:24px 26px;margin-bottom:16px;">'
        '<div style="display:flex;align-items:center;gap:10px;margin-bottom:4px;"><span style="width:7px;height:7px;border-radius:50%;background:#22c66e;"></span><h2 class="spaced" style="font-weight:600;font-size:18px;margin:0;">Matriz — produtos oferecidos por assessor</h2><span style="font-size:14px;color:#6a7589;font-weight:400;">nº de clientes a quem ofereceu</span></div>'
        '<div style="overflow-x:auto;margin-top:18px;"><table style="border-collapse:collapse;width:100%;min-width:760px;"><thead><tr>'
        '<th class="spaced" style="text-align:left;padding:0 14px 12px 6px;font-size:10.5px;font-weight:600;letter-spacing:0.14em;color:#5b6577;text-transform:uppercase;position:sticky;left:0;background:#0b101c;">Agente</th>'
        + mh + '</tr></thead><tbody>' + mrows
        + '<tr style="border-top:2px solid rgba(34,198,110,0.3);"><td class="spaced" style="padding:14px 14px 4px 6px;font-size:12px;font-weight:700;letter-spacing:0.1em;color:#e8edf5;position:sticky;left:0;background:#0b101c;">TOTAL</td>'
        + mtot + '</tr></tbody></table></div></div>'
    )

    pautas_block = (f'<div style="margin-top:8px;">{pautas_html}</div>' if pautas_html else "")

    V2CSS = """<style>
*{box-sizing:border-box;}html,body{margin:0;padding:0;}
body{background:#070a12;font-family:'Plus Jakarta Sans',sans-serif;-webkit-font-smoothing:antialiased;color:#e8edf5;}
::-webkit-scrollbar{width:9px;height:9px;}::-webkit-scrollbar-thumb{background:#1c2436;border-radius:6px;border:2px solid #070a12;}::-webkit-scrollbar-track{background:transparent;}
@keyframes fadeIn{from{opacity:0;transform:translateY(6px);}to{opacity:1;transform:translateY(0);}}
.spaced{font-family:'Space Grotesk',sans-serif;}
.v2nav:hover{background:rgba(255,255,255,0.04)!important;color:#e8edf5!important;}
.v2card{background:#0b101c;border:1px solid rgba(255,255,255,0.07);border-radius:16px;}
.card{background:#0b101c;border:1px solid rgba(255,255,255,0.07);border-radius:14px;padding:14px 18px;}
.advrow:hover{background:rgba(255,255,255,0.03);}
.advdetail{display:none;}.advdetail.on{display:block;animation:fadeIn .25s ease;}
</style>"""
    V2JS = """<script>
function selAdv(id){
  document.querySelectorAll('.advdetail').forEach(function(d){d.classList.remove('on');});
  var el=document.getElementById('adv-'+id); if(el)el.classList.add('on');
  document.querySelectorAll('.advrow').forEach(function(r){
    var on=r.getAttribute('data-id')===id, bar=r.getAttribute('data-selbar');
    r.style.background=on?'rgba(34,198,110,0.1)':'transparent';
    r.style.borderLeftColor=on?bar:'transparent';
    var nm=r.querySelector('.advname'); if(nm)nm.style.color=on?'#ffffff':'#d2d8e4';
  });
}
</script>"""

    topbar_html = (
        '<div style="display:flex;align-items:center;justify-content:space-between;gap:20px;margin-bottom:22px;flex-wrap:wrap;">'
        '<div style="display:flex;align-items:baseline;gap:14px;flex-wrap:wrap;">'
        '<h1 class="spaced" style="font-weight:700;font-size:30px;letter-spacing:-0.01em;margin:0;">Temas</h1>'
        f'<div style="display:flex;align-items:center;gap:7px;">{period_tabs}</div></div>'
        '<div style="display:flex;align-items:center;gap:14px;">'
        f'<span style="display:inline-flex;align-items:center;gap:7px;background:#0e1422;border:1px solid rgba(255,255,255,0.08);border-radius:9px;padding:4px 8px;"><select onchange="location.href=\'/dashboard/temas?canal=\'+this.value+\'&dias={dias}\'" style="background:transparent;border:none;color:#e8edf5;font-size:13px;font-weight:600;cursor:pointer;">{canal_opts}</select></span>'
        f'<div style="font-size:11.5px;color:#6a7589;font-family:{JM};">Atualizado {now_br.strftime("%H:%M")}</div>'
        '<a href="javascript:location.reload()" style="width:34px;height:34px;border-radius:9px;background:#0e1422;border:1px solid rgba(255,255,255,0.08);display:flex;align-items:center;justify-content:center;color:#9aa3b8;text-decoration:none;font-size:15px;">↻</a>'
        '</div></div>'
    )

    page = (
        "<!DOCTYPE html><html lang=\"pt-BR\"><head><meta charset=\"utf-8\">"
        "<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">"
        "<title>Temas — Alto Valor</title>"
        "<link rel=\"preconnect\" href=\"https://fonts.googleapis.com\"><link rel=\"preconnect\" href=\"https://fonts.gstatic.com\" crossorigin>"
        "<link href=\"https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@400;500;600;700&family=Plus+Jakarta+Sans:wght@400;500;600;700&family=JetBrains+Mono:wght@500;600;700&display=swap\" rel=\"stylesheet\">"
        + V2CSS +
        "</head><body><div style=\"display:flex;min-height:100vh;background:#070a12;color:#e8edf5;\">"
        + sidebar_html
        + "<main style=\"flex:1;min-width:0;padding:30px 36px 56px;max-width:1360px;\">"
        + topbar_html + metrics_html + split_html + lacunas_html + matriz_html + pautas_block
        + "</main></div>" + V2JS + "</body></html>"
    )

    return HTMLResponse(page)


# ── Clientes — carteira por assessor com resumo do último atendimento ─────────

def _clientes_data(db, access, canal: str, dias: int) -> list:
    """Linhas (assessor × cliente) com o resumo do último atendimento.

    Reaproveita o `resumo`/`motivo`/`nota` que a avaliação semanal já gerou
    (sem custo de IA). Para clientes ainda não avaliados, cai num preview da
    última mensagem. Uma linha por cliente, com a atividade mais recente do
    período selecionado."""
    from app.models import ConversationScore as _CS
    cutoff30 = (datetime.now(BRASILIA) - timedelta(days=30)).replace(
        hour=0, minute=0, second=0, microsecond=0).astimezone(timezone.utc)
    all_events, _cg, _cpl, cam, cnm = _load_period_pipeline(db, canal, cutoff30, 25000)
    # Resumo mais recente por telefone (avaliação roda no domingo).
    sc_window = (datetime.now(BRASILIA) - timedelta(days=45)).astimezone(timezone.utc)
    sc_by_phone: dict = {}
    for s in (db.query(_CS).filter(_CS.canal == canal, _CS.scored_at >= sc_window)
              .order_by(_CS.scored_at.asc()).all()):
        sc_by_phone[s.phone] = {
            "resumo": (s.resumo or "").strip(),
            "motivo": (s.motivo or "").strip(),
            "nota": s.nota if (s.nota is not None and s.nota >= 0) else None,
        }
    db.close()

    now_br = datetime.now(BRASILIA)
    if dias == 1:
        period_start = now_br.replace(hour=0, minute=0, second=0, microsecond=0)
    else:
        period_start = (now_br - timedelta(days=dias - 1)).replace(hour=0, minute=0, second=0, microsecond=0)
    cp = _real_phone(canal)
    _epoch = datetime.min.replace(tzinfo=timezone.utc)
    rows = []
    for client_num, evs in _cg.items():
        ph = _real_phone(client_num)
        if ph == cp:
            continue
        agent = _cpl.get(client_num) or cam.get(ph) or _cpl.get(ph) or "Sem atendente"
        if agent == "Sem atendente" or not _user_sees(access, agent):
            continue
        evs_sorted = sorted((e for e in evs if e.received_at), key=lambda e: e.received_at)
        last_ts = evs_sorted[-1].received_at if evs_sorted else None
        if not last_ts or last_ts.astimezone(BRASILIA) < period_start:
            continue
        sc = sc_by_phone.get(ph) or {}
        resumo = sc.get("resumo") or ""
        if not resumo:
            for e in reversed(evs_sorted):
                t = _extract_content_preview(e.raw_payload or {}) or ""
                if t and not t.startswith("["):
                    resumo = "(sem resumo da IA) " + t[:140]
                    break
        rows.append({
            "agente": agent,
            "cliente": cnm.get(ph, "") or ph,
            "telefone": ph,
            "ultimo_dt": last_ts.astimezone(BRASILIA),
            "ultimo_str": last_ts.astimezone(BRASILIA).strftime("%d/%m/%Y %H:%M"),
            "motivo": sc.get("motivo") or "",
            "resumo": resumo,
            "nota": sc.get("nota"),
        })
    rows.sort(key=lambda r: (_short_agent_name(r["agente"]).lower(), -(r["ultimo_dt"] or _epoch.astimezone(BRASILIA)).timestamp()))
    return rows


@router.get("/dashboard/clientes", response_class=HTMLResponse, include_in_schema=False)
def dashboard_clientes(request: Request, db: Session = Depends(get_db)):
    access = _get_access(request, db)
    if access is None:
        return _auth_redirect()
    canal = _req_canal(request)
    _draw = request.query_params.get("dias", "7")
    dias = int(_draw) if _draw.isdigit() and int(_draw) in (1, 7, 15, 30) else 7

    rows = _clientes_data(db, access, canal, dias)
    agents = sorted({r["agente"] for r in rows}, key=lambda a: _short_agent_name(a).lower())

    _base = f"canal={canal}"
    _seg = "".join(
        f'<a href="?{_base}&dias={d}" class="{"active" if dias == d else ""}">{("Hoje" if d == 1 else str(d)+" dias")}</a>'
        for d in (1, 7, 15, 30)
    )
    ag_opts = '<option value="">Todos os assessores</option>' + "".join(
        f'<option value="{html_mod.escape(_short_agent_name(a))}">{html_mod.escape(_short_agent_name(a))}</option>' for a in agents)

    body_rows = ""
    for r in rows:
        nota = r["nota"]
        nota_html = (f'<span style="font-weight:700;color:{"#0fa968" if nota>=7 else "#eab308" if nota>=5 else "#ef4444"}">{nota}</span>'
                     if nota is not None else '<span style="color:#3a4a6a">—</span>')
        motivo_html = f'<span style="color:#c0c8d8">{html_mod.escape(r["motivo"])}</span>' if r["motivo"] else '<span style="color:#3a4a6a">—</span>'
        body_rows += (
            f'<tr data-agente="{html_mod.escape(_short_agent_name(r["agente"]))}">'
            f'<td style="white-space:nowrap;font-weight:600;color:#e8ecf1">{html_mod.escape(_short_agent_name(r["agente"]))}</td>'
            f'<td style="white-space:nowrap">{html_mod.escape(r["cliente"])}</td>'
            f'<td style="white-space:nowrap;font-family:\'JetBrains Mono\',monospace;font-size:11px;color:#8a96aa">{r["ultimo_str"]}</td>'
            f'<td>{motivo_html}</td>'
            f'<td style="color:#c0c8d8;line-height:1.45">{html_mod.escape(r["resumo"])}</td>'
            f'<td style="text-align:center">{nota_html}</td></tr>'
        )
    if not body_rows:
        body_rows = '<tr><td colspan="6" style="text-align:center;color:#4a5a7a;padding:40px">Nenhum cliente com atividade no período.</td></tr>'

    export_href = f"/dashboard/clientes/export?{_base}&dias={dias}"
    page = f"""<!DOCTYPE html><html><head><meta charset="utf-8">
<title>Clientes — Alto Valor</title>{COMMON_CSS}
<style>
  .cli-table th{{position:sticky;top:0;background:#0b1120;z-index:1}}
  .cli-table td{{vertical-align:top}}
</style>
</head><body>
{_nav_html("clientes", canal=canal, is_admin=(access or {}).get('role')=='admin', title="Clientes")}
<div class="container">
  <div style="display:flex;align-items:center;gap:12px;margin-bottom:6px;flex-wrap:wrap">
    <div class="period-btns">{_seg}</div>
    <span style="color:#4a5a7a;font-size:12px">{len(rows)} clientes · resumo do último atendimento</span>
    <a href="{export_href}" style="margin-left:auto;background:#0fa968;color:#04150c;font-weight:700;font-size:12px;text-decoration:none;padding:8px 16px;border-radius:8px">&#11015; Exportar Excel</a>
  </div>
  <p style="font-size:11px;color:#5a6a8a;margin:0 0 14px">O resumo vem da avaliação automática de domingo. Clientes ainda não avaliados mostram um trecho da última mensagem.</p>

  <div class="card" style="margin-bottom:14px;display:flex;gap:10px;flex-wrap:wrap;align-items:center">
    <input id="cli-q" oninput="cliFilter()" placeholder="Buscar cliente, assessor ou assunto..." style="flex:1;min-width:220px;background:#0b1120;border:1px solid #1a2540;border-radius:8px;color:#e8ecf1;padding:9px 12px;font-size:13px">
    <select id="cli-ag" onchange="cliFilter()" style="background:#0b1120;border:1px solid #1a2540;border-radius:8px;color:#e8ecf1;padding:9px 12px;font-size:13px">{ag_opts}</select>
  </div>

  <div class="card">
    <div class="temas-scroll" style="overflow-x:auto">
      <table class="cli-table" style="width:100%">
        <thead><tr>
          <th style="min-width:130px">Assessor</th>
          <th style="min-width:150px">Cliente</th>
          <th style="min-width:120px">Último contato</th>
          <th style="min-width:120px">Motivo</th>
          <th style="min-width:280px">Resumo do atendimento</th>
          <th style="text-align:center">Nota</th>
        </tr></thead>
        <tbody id="cli-body">{body_rows}</tbody>
      </table>
    </div>
  </div>
</div>
<script>
function cliFilter(){{
  var q=(document.getElementById('cli-q').value||'').toLowerCase();
  var ag=document.getElementById('cli-ag').value;
  var n=0;
  document.querySelectorAll('#cli-body tr').forEach(function(tr){{
    if(!tr.dataset.agente){{return;}}
    var okAg=!ag||tr.dataset.agente===ag;
    var okQ=!q||tr.textContent.toLowerCase().indexOf(q)>=0;
    var show=okAg&&okQ; tr.style.display=show?'':'none'; if(show)n++;
  }});
}}
</script>
</body></html>"""
    return HTMLResponse(page)


@router.get("/dashboard/clientes/export", include_in_schema=False)
def dashboard_clientes_export(request: Request, db: Session = Depends(get_db)):
    """Exporta a tabela de Clientes em .xlsx (fallback CSV se openpyxl faltar)."""
    from fastapi.responses import StreamingResponse
    access = _get_access(request, db)
    if access is None:
        return RedirectResponse("/dashboard/login", status_code=302)
    canal = _req_canal(request)
    _draw = request.query_params.get("dias", "7")
    dias = int(_draw) if _draw.isdigit() and int(_draw) in (1, 7, 15, 30) else 7

    rows = _clientes_data(db, access, canal, dias)
    headers = ["Assessor", "Cliente", "Telefone", "Último contato", "Motivo", "Resumo do atendimento", "Nota"]
    stamp = datetime.now(BRASILIA).strftime("%Y%m%d_%H%M")
    fname = f"clientes_{dias}d_{stamp}"

    def _r(r):
        return [_short_agent_name(r["agente"]), r["cliente"], r["telefone"], r["ultimo_str"],
                r["motivo"], r["resumo"], (r["nota"] if r["nota"] is not None else "")]

    try:
        from openpyxl import Workbook
        from openpyxl.styles import Font, Alignment, PatternFill
        from openpyxl.utils import get_column_letter
        wb = Workbook(); ws = wb.active; ws.title = "Clientes"
        ws.append(headers)
        for r in rows:
            ws.append([_formula_safe(x) for x in _r(r)])
        hdr_fill = PatternFill("solid", fgColor="0B1120")
        for c in ws[1]:
            c.font = Font(bold=True, color="FFFFFF"); c.fill = hdr_fill
            c.alignment = Alignment(vertical="center")
        ws.freeze_panes = "A2"
        if rows:
            ws.auto_filter.ref = f"A1:{get_column_letter(len(headers))}{len(rows)+1}"
        for i, w in enumerate([24, 26, 15, 17, 22, 70, 7], start=1):
            ws.column_dimensions[get_column_letter(i)].width = w
        for row in ws.iter_rows(min_row=2, min_col=6, max_col=6):
            row[0].alignment = Alignment(wrap_text=True, vertical="top")
        buf = io.BytesIO(); wb.save(buf); buf.seek(0)
        return StreamingResponse(
            buf, media_type="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
            headers={"Content-Disposition": f'attachment; filename="{fname}.xlsx"'})
    except ImportError:
        # Fallback CSV (UTF-8 BOM p/ Excel) caso openpyxl não esteja instalado.
        def _csz(v):
            s = str(v)
            return ("'" + s) if s[:1] in ("=", "+", "-", "@") else s   # anti-injeção de fórmula
        output = io.StringIO(); output.write("﻿")
        writer = csv.writer(output, delimiter=";")
        writer.writerow(headers)
        for r in rows:
            writer.writerow([_csz(x) for x in _r(r)])
        output.seek(0)
        return StreamingResponse(
            iter([output.getvalue()]), media_type="text/csv; charset=utf-8",
            headers={"Content-Disposition": f'attachment; filename="{fname}.csv"'})


# ── Copiloto IA — v1 do atendimento assistido por IA ─────────────────────────
# Um grupo de clientes (telefones) definido pelo usuário é "atendido via
# plataforma". Para cada conversa, a IA sugere uma resposta SOB DEMANDA, com
# cache por (telefone, último evento) para não reprocessar nem estourar o teto
# diário de IA. O assessor revisa, edita e envia pela Zenvia. Base do futuro
# atendimento automático — nada é enviado sozinho nesta versão.

_COPILOTO_PHONES_KEY = "copiloto_phones"
_COPILOTO_SUGG_KEY   = "copiloto_sugg_cache"
_SUGG_CACHE_VER      = "r7"   # versão do prompt de sugestão; bump invalida o cache
_COPILOTO_SUGG_MAX   = 800   # limita o tamanho do cache de sugestões


def _normalize_phone_digits(raw: str) -> str:
    """Só dígitos; garante o código do país (55) para casar com o formato dos
    eventos (ex.: '5511991468874')."""
    import re as _re
    d = _re.sub(r"\D", "", raw or "")
    if not d:
        return ""
    if not d.startswith("55") and len(d) in (10, 11):
        d = "55" + d
    return d


def _parse_phone_list(text: str) -> list[str]:
    """Lê um bloco colado (um cliente por linha; aceita 'Nome - 5511...' ou
    '(11) 99999-9999'). Devolve telefones normalizados, sem duplicar, em ordem."""
    out: list[str] = []
    seen: set[str] = set()
    for line in (text or "").splitlines():
        d = _normalize_phone_digits(line)
        if len(d) >= 12 and d not in seen:   # 55 + 10/11 dígitos
            seen.add(d)
            out.append(d)
    return out


def _fmt_phone_br(p: str) -> str:
    import re as _re
    d = _re.sub(r"\D", "", p or "")
    if d.startswith("55"):
        d = d[2:]
    if len(d) == 11:
        return f"({d[:2]}) {d[2:7]}-{d[7:]}"
    if len(d) == 10:
        return f"({d[:2]}) {d[2:6]}-{d[6:]}"
    return p


def _crm_url(client_name: str) -> str:
    """Link de BUSCA no Salesforce (CRM) pelo código do cliente extraído do nome
    (ex.: 'NOME - 6930674'). Abre a busca; a conta vem como resultado top.
    Formato one.app base64 — validado no Salesforce da assessoria."""
    import re as _re, json as _json, base64 as _b64
    m = _re.search(r"(\d{4,})\s*$", client_name or "")
    if not m:
        return ""
    payload = {"componentDef": "forceSearch:searchPageDesktop",
               "attributes": {"term": m.group(1), "scopeMap": {"type": "TOP_RESULTS"}, "groupId": "DEFAULT"}}
    b = _b64.b64encode(_json.dumps(payload).encode()).decode()
    return "https://assessorxp.lightning.force.com/one/one.app#" + b


def _get_copiloto_stages(db) -> dict:
    """Pins manuais de etapa do Kanban {telefone: etapa}. Só as etapas comerciais
    (decisao/concluido) são pinadas; as de comunicação são automáticas."""
    import json as _json
    from app.crud import get_setting
    try:
        v = _json.loads(get_setting(db, "copiloto_stages") or "{}")
        return v if isinstance(v, dict) else {}
    except Exception:
        return {}


def _save_copiloto_stages(db, stages: dict) -> None:
    import json as _json
    from app.crud import set_setting
    set_setting(db, "copiloto_stages", _json.dumps(stages))


def _get_copiloto_phones(db) -> list[str]:
    import json as _json
    from app.crud import get_setting
    raw = get_setting(db, _COPILOTO_PHONES_KEY)
    if not raw:
        return []
    try:
        v = _json.loads(raw)
        return [str(x) for x in v] if isinstance(v, list) else []
    except Exception:
        return []


def _save_copiloto_phones(db, phones: list[str]) -> None:
    import json as _json
    from app.crud import set_setting
    set_setting(db, _COPILOTO_PHONES_KEY, _json.dumps(phones))


def _get_sugg_cache(db) -> dict:
    import json as _json
    from app.crud import get_setting
    raw = get_setting(db, _COPILOTO_SUGG_KEY)
    if not raw:
        return {}
    try:
        v = _json.loads(raw)
        return v if isinstance(v, dict) else {}
    except Exception:
        return {}


def _save_sugg_cache(db, cache: dict) -> None:
    import json as _json
    from app.crud import set_setting
    if len(cache) > _COPILOTO_SUGG_MAX:   # mantém as entradas mais recentes
        cache = dict(list(cache.items())[-_COPILOTO_SUGG_MAX:])
    set_setting(db, _COPILOTO_SUGG_KEY, _json.dumps(cache, ensure_ascii=False))


def _copiloto_data(db, access, phones: list[str], sugg_cache: dict):
    """Devolve (conversas, telefones_sem_conversa) para o grupo gerenciado.

    Faz uma query fresca (extrai tudo p/ dicts antes de fechar a sessão, evitando
    DetachedInstanceError) e escopa por _user_sees. Conversas com o cliente
    aguardando resposta (última msg IN) vêm primeiro."""
    import re as _re
    if not phones:
        return [], []
    managed = set(phones)
    managed_suffix = {p[-11:] for p in phones if len(p) >= 11}

    from app.crud import get_events_since, get_agent_mappings, get_client_names
    cutoff_utc = (datetime.now(BRASILIA) - timedelta(days=30)).replace(
        hour=0, minute=0, second=0, microsecond=0).astimezone(timezone.utc)
    raw_evs = get_events_since(db, since=cutoff_utc, limit=60000)
    raw_evs = _filter_events_by_channel(raw_evs, "")   # todos os canais
    cam = get_agent_mappings(db)
    cnm = get_client_names(db)
    groups_orm, phone_learned = _group_events(raw_evs, cam)
    _epoch = datetime.min.replace(tzinfo=timezone.utc)

    # Histórico de envios pelo Copiloto (registrado no Grampo), por sufixo de telefone.
    sent_map: dict = {}
    try:
        from app.models import CopilotoEnvio as _CE
        for r in (db.query(_CE).filter(_CE.status == "ok")
                  .order_by(_CE.sent_at.desc()).limit(400).all()):
            _suf = _re.sub(r"\D", "", r.phone or "")[-11:]
            sent_map.setdefault(_suf, []).append(r)
    except Exception:
        sent_map = {}
    stages_pins = _get_copiloto_stages(db)

    found: set[str] = set()
    convos: list[dict] = []
    for key, evs in groups_orm.items():
        phone = _real_phone(key)
        pd = _re.sub(r"\D", "", phone)
        if not (pd in managed or pd[-11:] in managed_suffix):
            continue
        msg_evs = [e for e in evs if (e.raw_payload or {}).get("type", "").upper()
                   not in ("MESSAGE_STATUS", "CONVERSATION_STATUS")]
        if not msg_evs:
            continue
        msg_evs.sort(key=lambda e: e.received_at or _epoch)
        last_ev = msg_evs[-1]
        if not last_ev.received_at:
            continue
        agent = (phone_learned.get(key) or cam.get(phone)
                 or phone_learned.get(phone) or "Sem atendente")
        if not _user_sees(access, agent):
            continue
        last_dir = _extract_direction(last_ev.raw_payload or {})
        last_text = _extract_content_preview(last_ev.raw_payload or {}, max_len=400) or ""
        conv_id = ""
        contact_name = ""
        canal_conv = ""
        for ev in msg_evs:
            _p = ev.raw_payload or {}
            _cid = (_p.get("conversation") or {}).get("id") or ""
            if _cid:
                conv_id = _cid
            if not canal_conv:
                _ch = _extract_channel(_p)
                if _ch:
                    canal_conv = _ch
            if not contact_name:
                _cn = _extract_contact_name(_p)
                if _cn:
                    contact_name = _cn
        last_event_id = str(last_ev.id)
        found.add(pd if pd in managed else next((p for p in phones if p[-11:] == pd[-11:]), pd))
        # Mensagens enviadas pelo Copiloto (via API) NÃO geram evento de webhook,
        # então o "last_dir" do inbound não enxerga que o assessor já respondeu.
        # Se o envio mais recente pelo Copiloto for POSTERIOR à última mensagem do
        # cliente, a bola está com o cliente → "aguardando cliente", não "para responder".
        _sent_list = sent_map.get(pd[-11:], [])
        _last_sent = _sent_list[0].sent_at if _sent_list else None
        if _last_sent is not None and _last_sent.tzinfo is None:
            _last_sent = _last_sent.replace(tzinfo=timezone.utc)
        replied_via_copiloto = bool(
            last_dir == "IN" and _last_sent is not None
            and _last_sent > last_ev.received_at.astimezone(timezone.utc)
        )
        effective_waiting = (last_dir == "IN") and not replied_via_copiloto
        convos.append({
            "phone":         phone,
            "agent":         agent,
            "client_name":   cnm.get(phone, "") or contact_name or _fmt_phone_br(phone),
            "last_text":     last_text,
            "last_dir":      last_dir,
            "last_ts":       last_ev.received_at.astimezone(BRASILIA),
            "last_ts_str":   last_ev.received_at.astimezone(BRASILIA).strftime("%d/%m %H:%M"),
            "last_event_id": last_event_id,
            "conv_id":       conv_id,
            "canal_conv":    canal_conv,
            "waiting":       effective_waiting,
            "replied_copiloto": replied_via_copiloto,
            "enviadas":      [{"ts": e.sent_at.astimezone(BRASILIA).strftime("%d/%m %H:%M"),
                               "text": (e.text or "")[:140],
                               "agent": _short_agent_name(agent)}   # assessor atual (não o gravado, p/ não defasar)
                              for e in sent_map.get(pd[-11:], [])[:3]],
            "suggestion":    sugg_cache.get(f"{phone}|{last_event_id}|{_SUGG_CACHE_VER}", ""),
            "stage":         (stages_pins.get(phone) if stages_pins.get(phone) in ("decisao", "concluido")
                              else ("para_responder" if effective_waiting else "aguardando_cliente")),
        })
    db.close()
    missing = [p for p in phones if p not in found]
    convos.sort(key=lambda c: (0 if c["waiting"] else 1, -c["last_ts"].timestamp()))
    return convos, missing


